#include <cstdio>

#include <cmath>

#include <algorithm>

#include <queue>

#include <iostream>

#include <vector>

#include <cstdlib>

#include <cstring>

#define eps 1e-6

#define ll long long

#define INF 0x3f3f3f3f

using namespace std;



char map[1005][1005];

int dis[1005][1005];

int dx[] = {0,0,1,-1};

int dy[] = {1,-1,0,0};

int row,col,n;

int current = 1;

int firstX,firstY;

int ans = 0;

typedef pair<int,int> pos;

queue <pos> q;



void bfs(){

    while(q.size()){

        pos t = q.front();

        q.pop();

        if(map[t.first][t.second] - '0'== current){

            ans += dis[t.first][t.second];

            current++;

            //清空队列保证下次起点正常

            while(q.size()){

                q.pop();

            }

            //重置距离数组

            memset(dis,INF,sizeof dis);

            dis[t.first][t.second] = 0;

            //设置下一次广搜的起点

            q.push(pos(t.first,t.second));

        }

        //四个方向进行bfs

        for(int i = 0;i<4;i++){

            int x = t.first + dx[i];

            int y = t.second + dy[i];

            if(x<0 || x>= row || y < 0|| y>=col || map[x][y] == 'X' || dis[x][y] != INF)//INF判断是否走过

                continue;

            else{

                q.push(pos(x,y));

                dis[x][y] = dis[t.first][t.second] + 1;

            }

        }

    }

}



int main(){

    cin>>row>>col>>n;

    //初始化

    ans = 0;

    memset(dis,INF,sizeof dis);

    for(int i = 0;i<row;i++){

        for(int j = 0;j<col;j++){

            cin>>map[i][j];

            if(map[i][j] == 'S'){

                //设置起点

                q.push(pos(i,j));

                dis[i][j] = 0;

            }

        }

    }

    //开始广搜

    bfs();

    cout<<ans<<endl;

    return 0;

}

